mapper.select:

	SELECT Top 1 A.LoginId		/*사용자ID*/
	, A.MemberID
	FROM XBOLTADM.TB_MEMBER A
	WHERE 1=1
	AND LoginId = #{LOGIN_ID}

	
		AND CompanyID = #{companyID}
	
	
		AND TeamID = #{teamID}
	
	Order By Active DESC, MemberID DESC

SELECT A.MemberID as USER_ID /*사용자ID*/ ,A.Name as USER_NM /*사용자명*/ ,A.LoginId as LOGIN_ID /*로그인ID*/ ,A.MemberID as AUTH_ID /* 권한 */ ,A.CompanyID as COMPANY_ID /*업체ID*/ ,A.CompanyID as SEL_CMPNY_ID /*업체ID*/ ,B.Name as COMPANY_NM /*업체명*/ ,ISNULL(A.TeamID, 0) as TEAM_ID /*상위업체ID*/ ,ISNULL(A.EmployeeNum, 0) as EMPLOYEE_NM /*사원번호*/ ,A.Authority as AUTH_LEV /*권한레벨*/ ,ISNULL(D.Name, '') as TEAM_NAME ,ISNULL(UE.LanguageID,#{LANGUAGE}) AS CURR_LANG_TYPE ,ISNULL(UE.Name,ISNULL(E.Name, #{LANGUAGE})) AS CURR_LANG_NM ,ISNULL(UE.LanguageCode,ISNULL(E.LanguageCode, #{LANGUAGE})) AS CURR_LANG_CODE /*LanguageCode*/ ,A.ClientID AS CLIENT_ID ,A.MLVL, ISNULL(E.FontFamily, 'Malgun Gothic') AS DEF_FONT ,ISNULL(E.FontSize,14) AS DEF_FONT_SIZE ,ISNULL(E.FontStyle,'1') AS DEF_FONT_STYLE ,ISNULL(E.FontColor,'black') AS DEF_FONT_COLOR ,ISNULL(A.Email,'') AS EMAIL ,ISNULL(A.DefLanguageID,(Select LanguageID From XBOLTADM.TB_LANGUAGE Where IsDefault = 1)) As DEF_LANGUAGE_ID /*Defult LanguageID*/ ,A.State AS STATE ,A.TimeZone AS USER_TIME_ZONE FROM XBOLTADM.TB_MEMBER A Left Outer Join XBOLTADM.TB_TEAM_TXT B on A.CompanyID = B.TeamID AND B.LanguageID = #{LANGUAGE} Left Outer Join XBOLTADM.TB_TEAM_TXT D on A.TeamID = D.TeamID AND D.LanguageID = #{LANGUAGE} LEFT OUTER JOIN XBOLTADM.TB_LANGUAGE UE ON UE.LanguageID = A.DefLanguageID LEFT OUTER JOIN XBOLTADM.TB_LANGUAGE E ON E.LanguageID = #{LANGUAGE} WHERE LoginId = #{LOGIN_ID}
AND Password = #{PASSWORD}
AND Active = #{active}
AND A.CompanyID = #{companyID}
AND A.teamID = #{teamID}
AND A.ClientID = #{clientID}
And ISNULL(A.Active,'') != '0'

Select A.MemberID AS CODE, ISNULL(E.Name,'')+'-'+ ISNULL(B.Name,'') AS NAME, C.TeamID AS TeamID, C.CompanyID AS CompanyID, C.ClientID AS ClientID, A.MLVL AS MLVL, A.Authority AS Authority From XBOLTADM.TB_MEMBER A, XBOLTADM.TB_TEAM_TXT B, XBOLTADM.TB_TEAM C, XBOLTADM.TB_TEAM D, XBOLTADM.TB_TEAM_TXT E Where A.TeamID = B.TeamID And B.LanguageID = #{languageID} And C.TeamID = A.TeamID And C.Deleted != 1 And ISNULL(A.Active,'') != '0' And D.Deleted != 1 And D.TeamID = A.CompanyID And D.TeamID = E.TeamID And E.LanguageID = #{languageID}
And A.LoginID = #{loginID}
AND A.MemberID = #{memberID}
AND A.EmployeeNum = #{employeeNum}
